import android.content.Context;
import android.content.SharedPreferences;
import android.hardware.fingerprint.FingerprintManager;
import android.os.Build;
import android.os.CancellationSignal;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import androidx.annotation.RequiresApi;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import java.security.KeyStore;
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;

public class FingerprintAuthManager {
    private static final String SHARED_PREFS_NAME = "biometric_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_ALIAS = "biometric_key";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    
    private Context context;
    private SharedPreferences sharedPreferences;
    private Cipher cipher;
    private FingerprintManager.CryptoObject cryptoObject;
    
    public FingerprintAuthManager(Context context) {
        this.context = context;
        this.sharedPreferences = context.getSharedPreferences(SHARED_PREFS_NAME, Context.MODE_PRIVATE);
    }
    
    public boolean isBiometricAuthEnabled() {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }
    
    public void setBiometricAuthEnabled(boolean enabled) {
        sharedPreferences.edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply();
    }
    
    @RequiresApi(api = Build.VERSION_CODES.M)
    public void initializeBiometricAuth() {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            
            if (!keyStore.containsAlias(KEY_ALIAS)) {
                KeyGenerator keyGenerator = KeyGenerator.getInstance(KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);
                keyGenerator.init(new KeyGenParameterSpec.Builder(KEY_ALIAS,
                        KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                        .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                        .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                        .setUserAuthenticationRequired(true)
                        .setInvalidatedByBiometricEnrollment(true)
                        .build());
                keyGenerator.generateKey();
            }
            
            cipher = Cipher.getInstance(KeyProperties.KEY_ALGORITHM_AES + "/" 
                    + KeyProperties.BLOCK_MODE_CBC + "/" 
                    + KeyProperties.ENCRYPTION_PADDING_PKCS7);
            cipher.init(Cipher.ENCRYPT_MODE, keyStore.getKey(KEY_ALIAS, null));
            cryptoObject = new FingerprintManager.CryptoObject(cipher);
            
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
    
    @RequiresApi(api = Build.VERSION_CODES.M)
    public void authenticate(BiometricPrompt.AuthenticationCallback callback) {
        BiometricPrompt prompt = new BiometricPrompt.Builder(context)
                .setTitle("Biometric Authentication")
                .setSubtitle("Unlock your app with fingerprint")
                .setDescription("Place your finger on the sensor")
                .setNegativeButtonText("Use password")
                .build();
        
        prompt.authenticate(new BiometricPrompt.CryptoObject(cipher), new CancellationSignal(), 
                ContextCompat.getMainExecutor(context), callback);
    }
    
    public boolean isBiometricAvailable() {
        BiometricManager biometricManager = BiometricManager.from(context);
        return biometricManager.canAuthenticate() == BiometricManager.BIOMETRIC_SUCCESS;
    }
}